CREATE OR REPLACE FUNCTION fpa_cnv_grop_pay_by_memno (as_memno char) RETURNS varchar AS $body$
DECLARE

  li_count integer;
  ls_return varchar(3);
  ls_mem_type sc_mem_m_membership_registered.mem_type%type;

BEGIN
  begin
    select mem_type
    into STRICT  ls_mem_type
    from  sc_mem_m_membership_registered
    where (membership_no = as_memno);
  exception when others then CALL spa_dberror('select memregis');
  end;
  case trim(both ls_mem_type)
   when '01' then  --สมาชิกปกติที่มีหมายเลขบัญชีธนาคารที่คีร์แล้วให้อัพเดดเป็นโอนเงินเข้าธนาคาร
      begin
       select count(membership_no) into STRICT li_count
       from   sc_mem_m_member_bank_accno
       where (membership_no = as_memno)
       and (paid_dividen = '1');
      exception when others then CALL spa_dberror('select membank');
      end;
      if li_count > 0 then
        ls_return := 'TRB';
      else
        ls_return := 'CSH';
      end if;
    when '02' then
     begin
      select  count(deposit_account_no) into STRICT li_count
      from    sc_dep_m_creditor
      where (membership_no = as_memno)
      and (close_status = '0');
     exception when others then CALL spa_dberror('select creditor');
     end;
     if li_count > 0 then
        ls_return := 'TRD';
    else
        ls_return := 'CSH';
    end if;
    else
     CALL spa_dberror('mem_type Not case! support');
  end case;


return   ls_return;

exception when others then CALL spa_dberror('FPA_CNV_GROP_PAY_BY_MEMNO');return null;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
